<template>
  <q-layout view="lHh Lpr lFf" class="course-learning">
    <q-page-container><q-page class="course-learning__page">
      <div v-if="loading" class="course-learning__loading"><q-spinner color="teal-3" size="42px" /></div>
      <div v-else-if="course" class="course-learning__shell">
        <header class="course-learning__header"><router-link to="/app" class="course-learning__back"><q-icon name="mdi-arrow-left" /> Minha area</router-link><div><span class="course-learning__eyebrow">AITOLEARN</span><strong>{{ course.title }}</strong></div></header>
        <div v-if="course.accessMode === 'early_access'" class="course-learning__early-note"><q-icon name="mdi-clock-fast" /><span><strong>Acesso antecipado</strong> Os videos comecam a subir em breve. Acompanhe esta trilha enquanto novas aulas sao publicadas.</span></div>
        <div class="course-learning__layout">
          <aside class="course-learning__topics"><p class="course-learning__eyebrow">Trilha</p><button v-for="topic in topics" :key="topic._id" type="button" :class="{ active: activeTopic?._id === topic._id }" @click="selectTopic(topic)"><q-icon :name="topic.completed ? 'mdi-check-circle' : topic.lessonUrl ? 'mdi-play-circle-outline' : 'mdi-clock-outline'" /><span>{{ topic.title }}</span></button><div class="course-learning__progress"><span>Progresso</span><strong>{{ progress }}%</strong><div><i :style="{ width: `${progress}%` }"></i></div></div></aside>
          <main class="course-learning__main">
            <div v-if="activeTopic" class="course-learning__lesson">
              <div class="course-learning__lesson-head"><p class="course-learning__eyebrow">Aula {{ String((activeTopic.position || 0) + 1).padStart(2, '0') }}</p><h1>{{ activeTopic.title }}</h1><a v-if="activeTopic.lessonUrl" :href="activeTopic.lessonUrl" target="_blank" rel="noopener noreferrer" class="course-learning__external"><q-icon name="mdi-open-in-new" /> Abrir aula</a></div>
              <div v-if="activeTopic.lessonUrl" class="course-learning__video"><iframe :src="activeTopic.lessonUrl" :title="activeTopic.title" allowfullscreen loading="lazy"></iframe></div>
              <div v-else class="course-learning__upcoming"><q-icon name="mdi-video-clock-outline" size="42px" /><strong>Video em breve</strong><span>Esta aula esta na fila de publicacao. Voce ja pode acompanhar a trilha e voltar quando o conteudo estiver disponivel.</span></div>
              <div class="course-learning__notes"><p class="course-learning__eyebrow">Anotacoes</p><p>{{ activeTopic.notes || 'Esta aula ainda nao possui anotacoes.' }}</p></div>
              <q-btn unelevated no-caps class="course-learning__complete" :loading="saving" :disable="activeTopic.completed || !activeTopic.lessonUrl" :label="activeTopic.completed ? 'Aula concluida' : 'Marcar aula como concluida'" :icon="activeTopic.completed ? 'mdi-check' : 'mdi-check-circle-outline'" @click="completeTopic" />
              <section class="course-learning__comments"><div class="course-learning__comments-head"><div><p class="course-learning__eyebrow">Comunidade</p><h2>Comentarios da aula</h2></div></div><q-form class="course-learning__comment-form" @submit.prevent="sendComment"><q-input v-model="commentText" outlined type="textarea" autogrow label="Escreva uma pergunta ou insight" :rules="[requiredRule]" /><q-btn unelevated no-caps class="course-learning__complete" type="submit" label="Publicar" icon="mdi-send" :loading="commenting" /></q-form><div class="course-learning__comment-list"><article v-for="comment in rootComments" :key="comment._id" class="course-comment"><div><strong>{{ comment.user?.name || 'Usuario' }}</strong><small>{{ formatDate(comment.createdAt) }}</small></div><p>{{ comment.body }}</p><div class="course-comment__actions"><button type="button" @click="replyTo = comment">Responder</button><button v-if="canDelete(comment)" type="button" @click="removeComment(comment)">Excluir</button></div><div v-for="reply in replies(comment._id)" :key="reply._id" class="course-comment course-comment--reply"><div><strong>{{ reply.user?.name || 'Usuario' }}</strong><small>{{ formatDate(reply.createdAt) }}</small></div><p>{{ reply.body }}</p><div class="course-comment__actions"><button v-if="canDelete(reply)" type="button" @click="removeComment(reply)">Excluir</button></div></div></article><span v-if="!rootComments.length" class="course-learning__empty">Seja a primeira pessoa a comentar.</span></div><q-banner v-if="replyTo" rounded class="course-learning__reply">Respondendo a {{ replyTo.user?.name }} <q-btn flat round dense icon="mdi-close" @click="replyTo = null" /></q-banner></section>
              <section v-if="course.attachments?.length" class="course-learning__attachments"><div><p class="course-learning__eyebrow">Materiais do curso</p><h2>Arquivos para continuar</h2></div><a v-for="attachment in course.attachments" :key="attachment.id" :href="attachment.url" target="_blank" rel="noopener noreferrer"><q-icon name="mdi-paperclip" /><span>{{ attachment.name }}</span><q-icon name="mdi-download-outline" /></a></section>
            </div>
            <div v-else class="course-learning__empty">Nenhuma aula publicada ainda.</div>
          </main>
        </div>
      </div>
      <div v-else class="course-learning__loading">Acesso nao encontrado.</div>
    </q-page></q-page-container>
  </q-layout>
</template>

<script setup>
import { computed, onMounted, ref } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { useQuasar } from 'quasar'
import { api } from 'boot/axios'

const route = useRoute(); const router = useRouter(); const $q = useQuasar(); const course = ref(null); const topics = ref([]); const comments = ref([]); const activeTopic = ref(null); const loading = ref(true); const saving = ref(false); const commenting = ref(false); const commentText = ref(''); const replyTo = ref(null)
const token = localStorage.getItem('aito_user_token'); const headers = { headers: { Authorization: `Bearer ${token}` } }; const rootComments = computed(() => comments.value.filter((item) => !item.parentComment || item.parentComment === null)); const progress = computed(() => Math.round(topics.value.filter((item) => item.completed).length / Math.max(topics.value.length, 1) * 100))
function requiredRule (value) { return Boolean(String(value || '').trim()) || 'Escreva algo.' }
function formatDate (value) { return value ? new Date(value).toLocaleDateString('pt-BR') : '-' }
function replies (id) { return comments.value.filter((item) => String(item.parentComment || '') === String(id)) }
function canDelete (comment) { return String(comment.user?.id || comment.user?._id || '') === String(JSON.parse(localStorage.getItem('aito_user') || '{}').id || '') }
function selectTopic (topic) { activeTopic.value = topic; api.post(`/courses/${route.params.slug}/view`, { topicId: topic._id }, headers).catch(() => null) }
async function load () { if (!token) { router.push('/app'); return } try { const response = await api.get(`/courses/${route.params.slug}/access`, headers); const data = response.data.data; course.value = data.course; topics.value = data.topics || []; comments.value = data.comments || []; activeTopic.value = topics.value[0] || null; if (activeTopic.value) selectTopic(activeTopic.value) } catch (error) { $q.notify({ type: 'negative', message: error.response?.data?.message || 'Nao foi possivel abrir o curso.' }); router.push('/app') } finally { loading.value = false } }
async function completeTopic () { if (!activeTopic.value?.lessonUrl) return; saving.value = true; try { const response = await api.post(`/courses/${route.params.slug}/topics/${activeTopic.value._id}/progress`, {}, headers); activeTopic.value.completed = true; const index = topics.value.findIndex((item) => item._id === activeTopic.value._id); if (index >= 0) topics.value[index].completed = true; if (response.data.data.certificate) $q.dialog({ title: 'Certificado gerado', message: 'Parabens! Seu certificado ja esta disponivel em Meus certificados.', ok: 'Ver certificados' }).onOk(() => router.push('/app')) } catch (error) { $q.notify({ type: 'negative', message: error.response?.data?.message || 'Nao foi possivel salvar o progresso.' }) } finally { saving.value = false } }
async function sendComment () { if (!commentText.value.trim() || !activeTopic.value) return; commenting.value = true; try { const response = await api.post(`/courses/${route.params.slug}/topics/${activeTopic.value._id}/comments`, { body: commentText.value, parentCommentId: replyTo.value?._id || null }, headers); comments.value.push(response.data.data); commentText.value = ''; replyTo.value = null } catch (error) { $q.notify({ type: 'negative', message: error.response?.data?.message || 'Nao foi possivel publicar.' }) } finally { commenting.value = false } }
async function removeComment (comment) { try { await api.delete(`/courses/comments/${comment._id}`, headers); comments.value = comments.value.filter((item) => item._id !== comment._id && item.parentComment !== comment._id) } catch (error) { $q.notify({ type: 'negative', message: 'Nao foi possivel excluir o comentario.' }) } }
onMounted(load)
</script>

<style scoped>
.course-learning{color:#effffb;background:#03090b}.course-learning__page{min-height:100vh;background:radial-gradient(circle at 80% 0,rgba(19,188,157,.14),transparent 28rem),#03090b}.course-learning__shell{width:min(1280px,calc(100% - 2rem));margin:auto;padding-bottom:3rem}.course-learning__header{display:flex;align-items:center;justify-content:space-between;padding:1rem 0;border-bottom:1px solid rgba(19,188,157,.2)}.course-learning__header>div{display:grid;gap:.2rem;text-align:right}.course-learning__header strong{font-size:.8rem}.course-learning__back{display:inline-flex;gap:.3rem;align-items:center;color:#8fffee;text-decoration:none;font-size:.75rem}.course-learning__eyebrow{margin:0;color:#8fffee;font-size:.64rem;font-weight:900;letter-spacing:.14em;text-transform:uppercase}.course-learning__early-note{display:flex;align-items:flex-start;gap:.6rem;margin-top:1rem;padding:.85rem 1rem;border:1px solid rgba(143,255,238,.25);border-radius:.6rem;color:#8fffee;background:rgba(19,188,157,.08);font-size:.74rem;line-height:1.5}.course-learning__layout{display:grid;grid-template-columns:250px 1fr;gap:1rem;padding-top:2rem}.course-learning__topics{align-self:start;position:sticky;top:1rem;display:grid;gap:.45rem;padding:1rem;border:1px solid rgba(19,188,157,.2);border-radius:.7rem;background:rgba(4,24,25,.72)}.course-learning__topics button{display:grid;grid-template-columns:auto 1fr;gap:.45rem;align-items:center;padding:.65rem;border:0;border-radius:.45rem;color:rgba(239,255,251,.67);background:transparent;text-align:left;cursor:pointer;font:inherit;font-size:.72rem}.course-learning__topics button.active,.course-learning__topics button:hover{color:#03110f;background:linear-gradient(135deg,#8fffee,#13bc9d)}.course-learning__progress{display:grid;gap:.4rem;margin-top:1rem;padding-top:.8rem;border-top:1px solid rgba(19,188,157,.16);font-size:.7rem}.course-learning__progress strong{color:#8fffee}.course-learning__progress>div{height:5px;overflow:hidden;border-radius:5px;background:rgba(143,255,238,.12)}.course-learning__progress i{display:block;height:100%;background:#13bc9d}.course-learning__main{min-width:0}.course-learning__lesson{display:grid;gap:1rem}.course-learning__lesson-head h1{max-width:18ch;margin:.45rem 0;font-size:clamp(2rem,5vw,4rem);line-height:1}.course-learning__external{display:inline-flex;align-items:center;gap:.3rem;color:#8fffee;font-size:.72rem;text-decoration:none}.course-learning__video{overflow:hidden;aspect-ratio:16/9;border:1px solid rgba(19,188,157,.28);border-radius:.75rem;background:#020b0c}.course-learning__video iframe{width:100%;height:100%;border:0}.course-learning__upcoming{display:grid;justify-items:center;gap:.55rem;padding:4rem 1rem;border:1px solid rgba(19,188,157,.23);border-radius:.75rem;color:rgba(239,255,251,.65);background:rgba(4,24,25,.62);text-align:center}.course-learning__upcoming .q-icon{color:#8fffee}.course-learning__upcoming strong{color:#effffb}.course-learning__upcoming span{max-width:34rem;line-height:1.5}.course-learning__notes{padding:1rem;border-left:2px solid #13bc9d;background:rgba(4,24,25,.62)}.course-learning__notes p:last-child{margin:.45rem 0 0;color:rgba(239,255,251,.7);white-space:pre-wrap;line-height:1.6}.course-learning__complete{width:max-content;color:#03110f;background:linear-gradient(135deg,#8fffee,#13bc9d);font-weight:900}.course-learning__comments,.course-learning__attachments{display:grid;gap:1rem;margin-top:2rem;padding-top:1.5rem;border-top:1px solid rgba(19,188,157,.16)}.course-learning__comments h2,.course-learning__attachments h2{margin:.4rem 0 0;font-size:1.3rem}.course-learning__comment-form{display:flex;align-items:flex-start;gap:.6rem}.course-learning__comment-form :deep(.q-field){flex:1}.course-learning__comment-form :deep(.q-field__control){color:#effffb;background:rgba(7,40,40,.72)}.course-learning__comment-list{display:grid;gap:.6rem}.course-comment{padding:.8rem;border:1px solid rgba(19,188,157,.18);border-radius:.55rem;background:rgba(4,24,25,.62)}.course-comment>div:first-child{display:flex;justify-content:space-between;gap:.7rem}.course-comment strong{font-size:.75rem;color:#8fffee}.course-comment small{color:rgba(229,255,250,.45);font-size:.63rem}.course-comment p{margin:.5rem 0;color:rgba(239,255,251,.75);font-size:.78rem;line-height:1.5;white-space:pre-wrap}.course-comment__actions{display:flex;gap:.6rem}.course-comment__actions button{border:0;color:#50dcc4;background:none;cursor:pointer;font-size:.67rem}.course-comment--reply{margin:.6rem 0 0 1.4rem;background:rgba(7,40,40,.55)}.course-learning__reply{display:flex;justify-content:space-between;color:#03110f;background:#8fffee}.course-learning__attachments a{display:flex;align-items:center;gap:.6rem;padding:.75rem;border:1px solid rgba(19,188,157,.18);border-radius:.55rem;color:#effffb;background:rgba(4,24,25,.62);text-decoration:none;font-size:.75rem}.course-learning__attachments a span{flex:1}.course-learning__attachments a .q-icon{color:#8fffee}.course-learning__empty,.course-learning__loading{display:grid;place-items:center;min-height:260px;color:rgba(239,255,251,.58)}@media(max-width:800px){.course-learning__layout{grid-template-columns:1fr}.course-learning__topics{position:static}.course-learning__comment-form{display:grid}.course-learning__complete{width:100%}}
</style>
